    try:
        # Decode the base64 string to bytes
        decoded_bytes = base64.b64decode(encoded_prefs)

        # Deserialize the pickled object
        preferences = pickle.loads(decoded_bytes)

        # Ensure the result is a dictionary, as expected
        if not isinstance(preferences, dict):
            return {}

        return preferences
    except Exception:
        # Handle errors gracefully: invalid base64, invalid pickle, or wrong type
        return {}

